def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    # Use VLM to check that the list has now been changed to use Roman numerals
    try:
        orig_slide_8 = None
        mod_slide_8 = None

        # Find slide 8 screenshots
        for screenshot in original_ppt_screenshots:
            if screenshot.slide_number == 8:
                orig_slide_8 = screenshot.image_path
                break

        for screenshot in modified_ppt_screenshots:
            if screenshot.slide_number == 8:
                mod_slide_8 = screenshot.image_path
                break

        if not orig_slide_8 or not mod_slide_8:
            raise ScreenshotsUnavailableError("Could not find slide 8 screenshots for comparison; flagging task for verification retry.")

        prompt = """Compare the first image (original) and the second image (modified) and evaluate whether the list has been changed to use Roman numerals.
        Respond with either "SUCCESS" if the list has been changed to use Roman numerals, or "FAILURE" followed by a brief explanation of what you observe."""

        response = vlm_call(prompt, [orig_slide_8, mod_slide_8], temperature=0.3)

        # Parse the score from the response
        import re
        score_match = re.search(r'(SUCCESS|FAILURE)', response)
        if score_match:
            score = float(score_match.group(1) == 'SUCCESS')
            return f"Roman numeral list format implemented correctly: {response}", score
        else:
            return f"Could not parse score from VLM response: {response}", 0.0

    except Exception as e:
        return f"Error comparing Roman numeral list format: {str(e)}", 0

